solution:
interface UserCardProps {
  name: string;
  email: string;
  role: string;
}

function UserCard({ name, email, role }: UserCardProps) {
  const initial = name.charAt(0).toUpperCase();

  return (
    <div className="card">
      <div className="avatar">{initial}</div>
      <div>
        <h3>{name}</h3>
        <p>{email}</p>
        <span className="badge">{role}</span>
      </div>
    </div>
  );
}

export default UserCard;
